        // Map x to [-6, 6]V, and z to [-6, 6]V
        // V_out = (x / 24) * 6 = x * 0.25
        // V_out = ((z / 55) * 2 - 1) * 6
        float out_ax = att_a.x * 0.25f * mag_a;
        float out_az = ((att_a.z / 55.f) * 2.f - 1.f) * 6.f * mag_a;
